## FILE 2: C:\Users\User\citedby-public\pages\Login.tsx

Gold-themed login page adapted from the PRO version. Replace all purple references with gold/amber.

```tsx
import React, { useState } from 'react';
import { Mail, Lock, ArrowRight, Loader2, Github, AlertCircle, User as UserIcon } from 'lucide-react';
import { User } from '../types';

interface LoginProps {
  onLogin: (user: User) => void;
  onBack: () => void;
}

const Login: React.FC<LoginProps> = ({ onLogin, onBack }) => {
  const [isRegistering, setIsRegistering] = useState(false);
  const [socialProvider, setSocialProvider] = useState<'google' | 'github' | null>(null);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const initSocialLogin = (provider: 'google' | 'github') => {
    setSocialProvider(provider);
    setIsLoading(false);
  };

  const finalizeSocialLogin = async (provider: 'google' | 'github') => {
    setIsLoading(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    const mockUser: User = {
      id: `${provider}_${Math.random().toString(36).substr(2, 9)}`,
      name: provider === 'google' ? 'Utilisateur Google' : 'Developpeur GitHub',
      email: provider === 'google' ? 'user@gmail.com' : 'dev@github.com',
      plan: 'free',
      credits: 50
    };
    onLogin(mockUser);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);
    await new Promise(resolve => setTimeout(resolve, 1500));
    if (!email || password.length < 4) {
      setError('Identifiants invalides. Le mot de passe doit contenir au moins 4 caracteres.');
      setIsLoading(false);
      return;
    }
    if (isRegistering) {
      if (password !== confirmPassword) { setError("Les mots de passe ne correspondent pas."); setIsLoading(false); return; }
      if (!name) { setError("Veuillez renseigner votre nom."); setIsLoading(false); return; }
    }
    const mockUser: User = {
      id: 'user_' + Math.random().toString(36).substr(2, 9),
      name: isRegistering ? name : email.split('@')[0],
      email, plan: 'free', credits: 50
    };
    onLogin(mockUser);
  };

  const toggleMode = () => { setIsRegistering(!isRegistering); setError(''); setPassword(''); setConfirmPassword(''); };

  // Mock Google login
  if (socialProvider === 'google') {
    return (
      <div className="min-h-screen bg-white flex items-center justify-center font-sans text-gray-800 animate-in fade-in zoom-in duration-300">
